/**
 * @summary Recent platform activity feed
 */
export const getGetRecentActivityUrl = (params?: GetRecentActivityParams) => {
  const normalizedParams = new URLSearchParams();

  Object.entries(params || {}).forEach(([key, value]) => {
    if (value !== undefined) {
      normalizedParams.append(key, value === null ? "null" : value.toString());
    }
  });

  const stringifiedParams = normalizedParams.toString();

  return stringifiedParams.length > 0
    ? `/api/analytics/activity?${stringifiedParams}`
    : `/api/analytics/activity`;
};

export const getRecentActivity = async (
  params?: GetRecentActivityParams,
  options?: RequestInit,
): Promise<ActivityEvent[]> => {
  return customFetch<ActivityEvent[]>(getGetRecentActivityUrl(params), {
    ...options,
    method: "GET",
  });
};

